-- 기본 활성화 (타임아웃 3600초)
ALTER SESSION ENABLE RESUMABLE;

-- 타임아웃 및 이름 지정
ALTER SESSION ENABLE RESUMABLE
  TIMEOUT 7200
  NAME 'Monthly_Data_Load';

-- 비활성화
ALTER SESSION DISABLE RESUMABLE;

-- 시스템 레벨에서 RESUMABLE_TIMEOUT 설정
ALTER SYSTEM SET RESUMABLE_TIMEOUT = 3600 SCOPE = BOTH;

-- PDB 레벨에서 설정 (멀티테넌트)
ALTER SYSTEM SET RESUMABLE_TIMEOUT = 1800 SCOPE = BOTH;

-- AFTER SUSPEND 트리거: 공간 부족 시 자동 데이터파일 확장
CREATE OR REPLACE TRIGGER auto_extend_on_suspend
AFTER SUSPEND ON DATABASE
DECLARE
  v_error_type    VARCHAR2(30);
  v_object_type   VARCHAR2(30);
  v_object_owner  VARCHAR2(128);
  v_table_space   VARCHAR2(128);
  v_object_name   VARCHAR2(128);
  v_sub_object    VARCHAR2(128);
BEGIN
  -- 공간 오류 정보 조회
  DBMS_RESUMABLE.SPACE_ERROR_INFO(
    error_type     => v_error_type,
    object_type    => v_object_type,
    object_owner   => v_object_owner,
    table_space_name => v_table_space,
    object_name    => v_object_name,
    sub_object_name => v_sub_object
  );

  -- 테이블스페이스 공간 부족인 경우 데이터파일 크기 자동 증가
  IF v_error_type = 'NO MORE SPACE' THEN
    -- DBA에게 알림 로그 기록
    DBMS_SYSTEM.KSDWRT(2,
      'RESUMABLE: Tablespace ' || v_table_space ||
      ' out of space for ' || v_object_type || ' ' ||
      v_object_owner || '.' || v_object_name);
  END IF;
END;
/

-- AFTER SUSPEND 트리거: DBA 알림 전용
CREATE OR REPLACE TRIGGER notify_on_suspend
AFTER SUSPEND ON SCHEMA
BEGIN
  -- 경고 로그에 기록
  DBMS_SYSTEM.KSDWRT(2,
    'RESUMABLE WARNING: Session ' || SYS_CONTEXT('USERENV', 'SID') ||
    ' suspended at ' || TO_CHAR(SYSDATE, 'YYYY-MM-DD HH24:MI:SS'));
END;
/

-- 현재 설정 값 확인
SHOW PARAMETER DEFERRED_SEGMENT_CREATION;

-- V$PARAMETER에서 상세 확인
SELECT name, value, isdefault, ismodified, issys_modifiable
FROM V$PARAMETER
WHERE name = 'deferred_segment_creation';

-- 시스템 레벨에서 비활성화 (모든 테이블 즉시 세그먼트 할당)
ALTER SYSTEM SET DEFERRED_SEGMENT_CREATION = FALSE SCOPE = BOTH;

-- 세션 레벨에서만 비활성화
ALTER SESSION SET DEFERRED_SEGMENT_CREATION = FALSE;

-- 다시 기본값(TRUE)으로 복원
ALTER SYSTEM SET DEFERRED_SEGMENT_CREATION = TRUE SCOPE = BOTH;

-- 멀티테넌트 환경: PDB별 설정 확인
SELECT con_id, name, value
FROM V$SYSTEM_PARAMETER
WHERE name = 'deferred_segment_creation';

-- 인덱스 클러스터 생성
CREATE CLUSTER hr.emp_dept_cluster (
  department_id NUMBER(4)
) SIZE 512;

-- 클러스터 인덱스 생성
CREATE INDEX hr.emp_dept_cluster_idx
  ON CLUSTER hr.emp_dept_cluster;

-- 클러스터드 테이블 생성
CREATE TABLE hr.emp_clustered (
  emp_id        NUMBER,
  emp_name      VARCHAR2(100),
  department_id NUMBER(4)
) CLUSTER hr.emp_dept_cluster (department_id);

-- 세그먼트 확인: 클러스터 자체에 세그먼트가 할당됨
SELECT segment_name, segment_type, bytes, blocks
FROM DBA_SEGMENTS
WHERE owner = 'HR'
  AND segment_name = 'EMP_DEPT_CLUSTER';

-- 클러스터드 테이블은 별도 세그먼트 없음 (클러스터 세그먼트 공유)
SELECT table_name, cluster_name, segment_created
FROM DBA_TABLES
WHERE owner = 'HR'
  AND table_name = 'EMP_CLUSTERED';

-- 트랜잭션 수준 GTT (기본값)
CREATE GLOBAL TEMPORARY TABLE hr.gtt_session_data (
  session_id NUMBER,
  data_value VARCHAR2(200)
) ON COMMIT DELETE ROWS;

-- 세션 수준 GTT
CREATE GLOBAL TEMPORARY TABLE hr.gtt_report_data (
  report_id   NUMBER,
  report_data CLOB
) ON COMMIT PRESERVE ROWS;

-- GTT는 DBA_TABLES에서 TEMPORARY = 'Y'
SELECT table_name, temporary, duration, tablespace_name
FROM DBA_TABLES
WHERE owner = 'HR'
  AND table_name LIKE 'GTT_%';

-- 데이터 삽입 후 임시 세그먼트 확인
INSERT INTO hr.gtt_session_data VALUES (1, 'test data');

-- 임시 세그먼트 사용 현황 확인
SELECT tablespace_name, current_users, total_blocks, used_blocks
FROM V$SORT_SEGMENT;
